// ✅ BUENAS PRÁCTICAS - API REST bien diseñada

// Recursos con sustantivos plurales
GET    /api/v1/customers          // Listar clientes
GET    /api/v1/customers/{id}     // Obtener cliente específico
POST   /api/v1/customers          // Crear cliente
PUT    /api/v1/customers/{id}     // Actualizar cliente
DELETE /api/v1/customers/{id}     // Eliminar cliente

// Recursos anidados (relaciones)
GET    /api/v1/customers/{id}/products        // Productos del cliente
POST   /api/v1/customers/{id}/products/{pid}  // Asociar producto

// ❌ MALAS PRÁCTICAS - Evitar

// Verbos en URL
POST   /api/createCustomer          // ❌ No usar verbos
GET    /api/getCustomerById/{id}    // ❌ Redundante

// Nombres inconsistentes
GET    /api/Customer                // ❌ Singular y mayúscula
GET    /api/get_customers           // ❌ Snake case

// Headers correctos
Content-Type: application/json
Accept: application/json
Authorization: Bearer {token}

// Estructura de respuesta JSON consistente
{
  "data": { /* recurso */ },
  "status": "success",
  "timestamp": "2024-01-15T10:30:00Z"
}
